import { useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';

export type Member = {
  name: string;
  position: string;
  profession: string;
  company: string;
  school: string;
  bio: string;
  photo: string | null;
  accent: string;
  gradient: string;
};

interface Props {
  member: Member;
  index: number;
  onSelect: (member: Member) => void;
}

function initials(name: string) {
  return name.split(' ').map((w) => w[0]).join('');
}

export function MemberCard({ member, index, onSelect }: Props) {
  const [hovered, setHovered] = useState(false);

  return (
    <motion.article
      initial={{ opacity: 0, y: 24 }}
      whileInView={{ opacity: 1, y: 0 }}
      viewport={{ once: true }}
      transition={{ duration: 0.45, delay: index * 0.055, ease: 'easeOut' }}
      onHoverStart={() => setHovered(true)}
      onHoverEnd={() => setHovered(false)}
      onClick={() => onSelect(member)}
      className="relative flex flex-col rounded-2xl overflow-hidden cursor-pointer select-none"
      style={{
        background: '#0d1117',
        border: `1px solid ${hovered ? member.accent + '55' : 'rgba(255,255,255,0.06)'}`,
        boxShadow: hovered
          ? `0 0 0 1px ${member.accent}30, 0 20px 60px -12px ${member.accent}30`
          : '0 1px 3px rgba(0,0,0,0.4)',
        transition: 'border-color 0.3s ease, box-shadow 0.3s ease',
      }}
    >
      {/* ── avatar header ── */}
      <div
        className="relative flex items-end justify-center pb-0 overflow-hidden"
        style={{ height: 120, background: '#0d1117' }}
      >
        {/* gradient splash behind avatar */}
        <div
          className="absolute inset-0"
          style={{
            background: member.gradient,
            opacity: 0.15,
            transition: 'opacity 0.35s ease',
            ...(hovered ? { opacity: 0.28 } : {}),
          }}
        />
        {/* noise overlay */}
        <svg className="absolute inset-0 w-full h-full pointer-events-none opacity-[0.04]" xmlns="http://www.w3.org/2000/svg">
          <filter id={`noise-${index}`}>
            <feTurbulence type="fractalNoise" baseFrequency="0.65" numOctaves="3" stitchTiles="stitch" />
            <feColorMatrix type="saturate" values="0" />
          </filter>
          <rect width="100%" height="100%" filter={`url(#noise-${index})`} />
        </svg>

        {/* avatar — overlaps the divide */}
        <motion.div
          animate={{ y: hovered ? -4 : 0 }}
          transition={{ type: 'spring', stiffness: 260, damping: 22 }}
          className="relative z-10 translate-y-1/2 rounded-full flex items-center justify-center overflow-hidden flex-shrink-0"
          style={{
            width: 80,
            height: 80,
            background: member.gradient,
            boxShadow: hovered
              ? `0 0 0 3px #0d1117, 0 0 0 5px ${member.accent}80, 0 8px 32px ${member.accent}50`
              : `0 0 0 3px #0d1117, 0 0 0 4px ${member.accent}40`,
            transition: 'box-shadow 0.35s ease',
          }}
        >
          {member.photo ? (
            <img src={member.photo} alt={member.name} className="w-full h-full object-cover" draggable={false} />
          ) : (
            <span className="font-black text-white text-2xl tracking-tight">{initials(member.name)}</span>
          )}
        </motion.div>
      </div>

      {/* ── body ── */}
      <div className="flex flex-col flex-1 pt-12 pb-5 px-5">

        {/* name + badge row */}
        <div className="flex items-start justify-between gap-2 mb-3">
          <h3 className="font-black text-[15px] leading-tight text-white">
            {member.name}
          </h3>
          <span
            className="shrink-0 text-[10px] font-bold uppercase tracking-wider px-2 py-0.5 rounded-md leading-5"
            style={{
              background: member.accent + '20',
              color: member.accent,
              border: `1px solid ${member.accent}30`,
            }}
          >
            {member.position.replace(' Director', '').replace(' President', ' Pres.')}
          </span>
        </div>

        {/* profession */}
        <p className="text-[13px] font-semibold leading-snug mb-4" style={{ color: '#7dd3fc' }}>
          {member.profession}
        </p>

        {/* divider */}
        <div className="mb-4" style={{ height: '1px', background: 'rgba(255,255,255,0.06)' }} />

        {/* meta */}
        <div className="flex flex-col gap-2">
          <div className="flex items-start gap-2">
            <svg className="mt-0.5 shrink-0" width="11" height="11" viewBox="0 0 24 24" fill="none" stroke={member.accent} strokeWidth="2">
              <path d="M3 9l9-7 9 7v11a2 2 0 01-2 2H5a2 2 0 01-2-2z" /><polyline points="9 22 9 12 15 12 15 22" />
            </svg>
            <span className="text-[12px] leading-tight" style={{ color: '#64748b' }}>{member.company}</span>
          </div>
          <div className="flex items-start gap-2">
            <svg className="mt-0.5 shrink-0" width="11" height="11" viewBox="0 0 24 24" fill="none" stroke={member.accent} strokeWidth="2">
              <path d="M22 10v6M2 10l10-5 10 5-10 5z" /><path d="M6 12v5c3 3 9 3 12 0v-5" />
            </svg>
            <span className="text-[12px] leading-tight" style={{ color: '#64748b' }}>{member.school}</span>
          </div>
        </div>

        {/* bio reveal */}
        <AnimatePresence initial={false}>
          {hovered && (
            <motion.div
              key="bio"
              initial={{ height: 0, opacity: 0 }}
              animate={{ height: 'auto', opacity: 1 }}
              exit={{ height: 0, opacity: 0 }}
              transition={{ duration: 0.28, ease: 'easeInOut' }}
              style={{ overflow: 'hidden' }}
            >
              <p className="text-[12px] leading-relaxed mt-4 pt-3" style={{ color: '#94a3b8', borderTop: '1px solid rgba(255,255,255,0.06)' }}>
                {member.bio}
              </p>
            </motion.div>
          )}
        </AnimatePresence>

        {/* cta */}
        <motion.div
          className="flex items-center gap-1.5 mt-4 text-[11px] font-bold uppercase tracking-widest"
          style={{ color: member.accent }}
          animate={{ x: hovered ? 3 : 0 }}
          transition={{ type: 'spring', stiffness: 380, damping: 26 }}
        >
          <span>Profile</span>
          <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round">
            <path d="M5 12h14M12 5l7 7-7 7" />
          </svg>
        </motion.div>
      </div>

      {/* top glow line */}
      <motion.div
        className="absolute top-0 left-0 right-0 h-px"
        animate={{ opacity: hovered ? 1 : 0 }}
        transition={{ duration: 0.3 }}
        style={{ background: member.gradient }}
      />
    </motion.article>
  );
}
